ground_truth_sql_postgres:
SELECT "Start_from"::int AS start_year, "Shop_ID" AS shop_id
FROM bench_nvbench_employee_hire_evaluation.hiring
ORDER BY start_year;

SELECT "Shop_ID" AS shop_id, "Employee_ID" AS employee_id
FROM bench_nvbench_employee_hire_evaluation.hiring
ORDER BY "Employee_ID";

SELECT student_id, address_id
FROM bench_nvbench_behavior_monitoring.student_addresses
ORDER BY monthly_rental DESC;
